#include <iostream>
#include <string>
#include <sstream>

// This driver simulates running the student's code with redirected I/O.
// In a real testing environment, the student's code would be compiled
// and executed as a separate process, with stdin/stdout pipes.

std::string run_student_code(const std::string& input) {
    std::istringstream iss(input);
    std::ostringstream oss;

    // Redirect std::cin and std::cout
    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cin.rdbuf(iss.rdbuf());
    std::cout.rdbuf(oss.rdbuf());

    // Call the student's main function (assuming it's refactored or linked)
    // For this dataset, we assume the main function of the .cpp file is executed.
    // The actual main() from the student's file would be called here.
    // main(); // This would be the conceptual call if linked as a function

    // Restore std::cin and std::cout
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    return oss.str();
}

